  1607→		pendingData[nPending].Samples = pendingData[nPending].Samples[:0]
  1608→		if sendExemplars {
  1609→			pendingData[nPending].Exemplars = pendingData[nPending].Exemplars[:0]
  1610→		}
  1611→		if sendNativeHistograms {
  1612→			pendingData[nPending].Histograms = pendingData[nPending].Histograms[:0]
  1613→		}
